    w("conundrum","bilmece","A confusing and difficult problem or question","noun","/kəˈnʌn.drəm/","The budget deficit is a conundrum.","It's a moral conundrum with no easy answer.","She faced the conundrum of choosing between two jobs."),
    w("debilitate","zayıflatmak","To make someone very weak","verb","/dɪˈbɪl.ɪ.teɪt/","The disease debilitated him for months.","Chronic stress can debilitate the immune system.","The injury debilitated the athlete."),
    w("delineate","belirlemek","To describe or portray something precisely","verb","/dɪˈlɪn.i.eɪt/","She delineated the boundaries of the project.","The report clearly delineates the risks involved.","It's important to delineate roles and responsibilities."),
    w("ebullient","coşkulu","Cheerful and full of energy","adjective","/ɪˈbʊl.i.ənt/","She was in an ebullient mood after the promotion.","His ebullient personality lights up every room.","The crowd was ebullient after the victory."),
    w("ephemeral","geçici","Lasting for a very short time","adjective","/ɪˈfem.ər.əl/","Social media fame is often ephemeral.","The beauty of cherry blossoms is ephemeral.","Ephemeral trends come and go quickly."),
    w("equivocal","iki anlamlı","Open to more than one interpretation; ambiguous","adjective","/ɪˈkwɪv.ə.kəl/","His response was deliberately equivocal.","The results of the study were equivocal.","She gave an equivocal answer to avoid commitment."),
    w("exacerbate","kötüleştirmek","To make a problem or situation worse","verb","/ɪɡˈzæs.ər.beɪt/","The drought exacerbated the food crisis.","Stress can exacerbate health problems.","His comments only exacerbated the tension."),
    w("fastidious","titiz","Very attentive to detail and accuracy","adjective","/fæsˈtɪd.i.əs/","She is fastidious about her work.","He kept his house in fastidious order.","The editor was fastidious about grammar."),
    w("gregarious","sosyal","Fond of company; sociable","adjective","/ɡrɪˈɡer.i.əs/","She has a gregarious personality.","He is naturally gregarious and makes friends easily.","Gregarious people thrive in social settings."),
    w("idiosyncratic","kendine özgü","Relating to a distinctive individual characteristic","adjective","/ˌɪd.i.ə.sɪŋˈkræt.ɪk/","She has an idiosyncratic sense of humor.","His writing style is highly idiosyncratic.","Each culture has its own idiosyncratic customs."),
